function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	g_form.showFieldMsg('u_template_subtask_s_name_setting', getMessage('Tasker - Template Subtask Prefix or Suffix Message'), 'info');
	g_form.showFieldMsg('short_description', getMessage('Tasker - Template and Template Instance Top Task Name field message'), 'info');
	if (isLoading || newValue === '') {
      return;
   }
}
